mapper.select:
select
jf.DWDM as dwdm,
jf.dept_id as deptId,
jf.jsbj as jsbj,
jf.cbjthbj as cbjthbj,
count(jf.djxh) as jfbs,
count(distinct jf.djxh) as jfhs,
sum(jf.YBTSE) as ybtse,
sum(jf.YFJE) as yfje,
sum(jf.GKZFJE) as gkzfje,
sum(jf.GJTHJE) as gjthje,
sum(jf.jcghje) as jcghje,
sum(jf.cbjje) as cbjje,
sum(jf.HYGHJE) as hyghje,
sum(jf.xjghje) as xjghje,
sum(jf.SJGHJE) as sjghje,
sum(jf.SZGHJE) as szghje,
sum(jf.QGGHJE) as qgghje,
sum(jf.sdsje) as sdsje,
sum(jf.swjgje) as swjgje
from xwqyjf jf

    1=1
    and jf.DWDM = #{req.dwdm}
    and jf.ND = #{req.nd}
    and jf.SHXYDM = #{req.shxydm}
    and jf.NSRMC like concat('%', #{req.nsrmc}, '%')
    and jf.xwsbdwdm = #{req.xwsbdwdm}
    and jf.xwsbrq between #{req.beginXwsbrq} and
        #{req.endXwsbrq}

    and jf.xwlx = #{req.xwlx}
    and (jf.dept_id = #{req.deptId} or jf.dept_id in (select t.dept_id from sys_dept t where find_in_set(#{req.deptId},
        ancestors)))

    and jf.HYGHBZ = #{req.hyghbz}
    and jf.GHLB_DM = #{req.ghlbDm}
    and jf.XTLB_DM = #{req.xtlbDm}
    and jf.ZSPM_DM = #{req.zspmDm}
    and jf.SKSSQQ = #{req.skssqq}
    and jf.SKSSQZ = #{req.skssqz}
    and jf.RKRQ between #{req.beginRkrq} and #{req.endRkrq}
    and jf.JSBJ = #{req.jsbj}
    and jf.JSRQ between #{req.beginJsrq} and #{req.endJsrq}
    and jf.CBJTHBJ = #{req.cbjthbj}
    and jf.CBJTHRQ between #{req.beginCbjthrq} and
        #{req.endCbjthrq}

    and jf.HKPCH = #{req.hkpch}

group by jf.DWDM, jf.dept_id, jf.jsbj, jf.cbjthbj
order by jf.DWDM

select
jf.DWDM as dwdm,
jf.dept_id as deptId,
jf.shxydm as shxydm,
jf.nsrmc as nsrmc,
jf.jsbj as jsbj,
jf.cbjthbj as cbjthbj,
