sum(jf.YBTSE) as ybtse,
sum(jf.YFJE) as yfje,
sum(jf.GKZFJE) as gkzfje,
sum(jf.GJTHJE) as gjthje,
sum(jf.jcghje) as jcghje,
sum(jf.cbjje) as cbjje,
sum(jf.HYGHJE) as hyghje,
sum(jf.xjghje) as xjghje,
sum(jf.SJGHJE) as sjghje,
sum(jf.SZGHJE) as szghje,
sum(jf.QGGHJE) as qgghje,
sum(jf.sdsje) as sdsje,
sum(jf.swjgje) as swjgje
from xwqyjf jf

    1=1
    and jf.DWDM = #{req.dwdm}
    and jf.ND = #{req.nd}
    and jf.SHXYDM = #{req.shxydm}
    and jf.NSRMC like concat('%', #{req.nsrmc}, '%')
    and jf.xwsbdwdm = #{req.xwsbdwdm}
    and jf.xwsbrq between #{req.beginXwsbrq} and
        #{req.endXwsbrq}

    and jf.xwlx = #{req.xwlx}
    and jf.dept_id = #{req.deptId}
    and jf.HYGHBZ = #{req.hyghbz}
    and jf.GHLB_DM = #{req.ghlbDm}
    and jf.XTLB_DM = #{req.xtlbDm}
    and jf.ZSPM_DM = #{req.zspmDm}
    and jf.SKSSQQ = #{req.skssqq}
    and jf.SKSSQZ = #{req.skssqz}
    and jf.RKRQ between #{req.beginRkrq} and #{req.endRkrq}
    and jf.JSBJ = #{req.jsbj}
    and jf.JSRQ between #{req.beginJsrq} and #{req.endJsrq}
    and jf.CBJTHBJ = #{req.cbjthbj}
    and jf.CBJTHRQ between #{req.beginCbjthrq} and
        #{req.endCbjthrq}

    and jf.HKPCH = #{req.hkpch}

group by jf.DWDM, jf.dept_id, jf.shxydm, jf.nsrmc, jf.jsbj, jf.cbjthbj
order by jf.DWDM

    limit #{req.offset}, #{req.pageSize}

select count(*) from (
select jf.DWDM
from xwqyjf jf

    1=1
    and jf.DWDM = #{req.dwdm}
    and jf.ND = #{req.nd}
    and jf.SHXYDM = #{req.shxydm}
    and jf.NSRMC like concat('%', #{req.nsrmc}, '%')
    and jf.xwsbdwdm = #{req.xwsbdwdm}
    and jf.xwsbrq between #{req.beginXwsbrq} and #{req.endXwsbrq}
    and jf.xwlx = #{req.xwlx}
    and jf.dept_id = #{req.deptId}
    and jf.HYGHBZ = #{req.hyghbz}
    and jf.GHLB_DM = #{req.ghlbDm}
    and jf.XTLB_DM = #{req.xtlbDm}
    and jf.ZSPM_DM = #{req.zspmDm}
    and jf.JSBJ = #{req.jsbj}
    and jf.CBJTHBJ = #{req.cbjthbj}
    and jf.HKPCH = #{req.hkpch}

group by jf.DWDM, jf.dept_id, jf.shxydm, jf.nsrmc, jf.jsbj, jf.cbjthbj
) t

select
DWDM as dwdm, ND as nd, ghjf_id as ghjfId, SPUUID as spuuid,
DJXH as djxh, SHXYDM as shxydm, NSRMC as nsrmc,
xwsbdwdm, xwsbrq, xwlx, NSRJC as nsrjc,
dept_id as deptId, GHJGXZJB as ghjgxzjb, CLGHBJ as clghbj,
HYGHBZ as hyghbz, SDGHJG_DM as sdghjgDm, SDGHJGXZJB as sdghjgxzjb,
ZGSWJ_DM as zgswjDm, ZGSWSKFJ_DM as zgswskfjDm, SSGLY_DM as ssglyDm,
GHLB_DM as ghlbDm, XTLB_DM as xtlbDm, ZZJGLX_DM as zzjglxDm,
HY_DM as hyDm, DJZCLX_DM as djzclxDm, DWLSGX_DM as dwlsgxDm,
SBLB_DM as sblbDm, NSSBRQ as nssbrq, PZXH as pzxh, PZMXXH as pzmxxh,
SKSSQQ as skssqq, SKSSQZ as skssqz, ZSSWJG_DM as zsswjgDm,
SKSSSWJG_DM as skssswjgDm,
ZSPM_DM as zspmDm, GZZE as gzze, SL as sl, YNSE as ynse,
JMSE as jmse, YJSE as yjse, YBTSE as ybtse,
YFJE as yfje, GKZFJE as gkzfje, GJTHJE as gjthje,
JSBJ as jsbj, JSRQ as jsrq,
JCGHJE as jcghje, CBJJE as cbjje, HYGHJE as hyghje,
XJGHJE as xjghje, SJGHJE as sjghje, SZGHJE as szghje,
QGGHJE as qgghje, SDSJE as sdsje, SWJGJE as swjgje,
CBJTHBJ as cbjthbj, HKPCH as hkpch, RKRQ as rkrq
from xwqyjf

    and DWDM = #{req.dwdm}
    and ND = #{req.nd}
    and SHXYDM = #{req.shxydm}
    and NSRMC like concat('%', #{req.nsrmc}, '%')
    and xwsbdwdm = #{req.xwsbdwdm}
    and xwsbrq between #{req.beginXwsbrq} and
        #{req.endXwsbrq}

    and xwlx = #{req.xwlx}
    and dept_id = #{req.deptId}
    and HYGHBZ = #{req.hyghbz}
    and GHLB_DM = #{req.ghlbDm}
    and XTLB_DM = #{req.xtlbDm}
    and ZSPM_DM = #{req.zspmDm}
    and SKSSQQ = #{req.skssqq}
    and SKSSQZ = #{req.skssqz}
    and RKRQ between #{req.beginRkrq} and #{req.endRkrq}
    and JSBJ = #{req.jsbj}
    and JSRQ between #{req.beginJsrq} and #{req.endJsrq}
    and CBJTHBJ = #{req.cbjthbj}
    and CBJTHRQ between #{req.beginCbjthrq} and
        #{req.endCbjthrq}

    and HKPCH = #{req.hkpch}


    limit #{req.offset}, #{req.pageSize}

select count(*)
from xwqyjf

    and DWDM = #{req.dwdm}
    and ND = #{req.nd}
    and SHXYDM = #{req.shxydm}
    and NSRMC like concat('%', #{req.nsrmc}, '%')
    and xwsbdwdm = #{req.xwsbdwdm}
    and xwsbrq between #{req.beginXwsbrq} and #{req.endXwsbrq}
    and xwlx = #{req.xwlx}
    and dept_id = #{req.deptId}
    and HYGHBZ = #{req.hyghbz}
    and GHLB_DM = #{req.ghlbDm}
    and XTLB_DM = #{req.xtlbDm}
    and ZSPM_DM = #{req.zspmDm}
    and JSBJ = #{req.jsbj}
